import React, { useState, useEffect } from 'react';
import {
  View,
  TouchableOpacity,
  Text,
  StyleSheet,
  Platform,
} from 'react-native';
import { Ionicons } from '@expo/vector-icons';
import { GooglePlacesAutocomplete, GooglePlacesAutocompleteRef } from 'react-native-google-places-autocomplete';
import { getFrequentLocations, addFrequentLocation } from '../utils/storage';
import { typography } from '../styles/typography';

// You'll need to get a Google Places API key from the Google Cloud Console
const GOOGLE_PLACES_API_KEY = 'YOUR_API_KEY';

interface LocationInputProps {
  value: string;
  onLocationSelect: (location: string) => void;
  onPinPress?: () => void;
}

export const LocationInput: React.FC<LocationInputProps> = ({
  value,
  onLocationSelect,
  onPinPress,
}) => {
  const [isEditing, setIsEditing] = useState(false);
  const [frequentLocations, setFrequentLocations] = useState<string[]>([]);

  // Load frequent locations on mount
  useEffect(() => {
    const loadFrequentLocations = async () => {
      const locations = await getFrequentLocations();
      setFrequentLocations(locations);
    };
    loadFrequentLocations();
  }, []);

  const handleLocationSelect = async (data: any, details: any = null) => {
    const formattedLocation = details?.formatted_address || data.description;
    await addFrequentLocation(formattedLocation);
    const locations = await getFrequentLocations();
    setFrequentLocations(locations);
    setIsEditing(false);
    onLocationSelect(formattedLocation);
  };

  return (
    <View style={styles.container}>
      {isEditing ? (
        <GooglePlacesAutocomplete
          placeholder="Search for a city..."
          onPress={handleLocationSelect}
          query={{
            key: GOOGLE_PLACES_API_KEY,
            language: 'en',
            types: '(cities)',
          }}
          fetchDetails={true}
          enablePoweredByContainer={false}
          onFail={error => console.warn(error)}
          styles={{
            container: styles.autocompleteContainer,
            textInput: [typography.body, styles.input],
            listView: styles.listView,
            row: styles.suggestion,
            description: typography.body,
          }}
          renderLeftButton={() => (
            <Ionicons name="location-outline" size={16} color="#757575" style={styles.icon} />
          )}
          renderRightButton={() => {
            if (onPinPress) {
              return (
                <TouchableOpacity onPress={onPinPress} style={styles.pinButton}>
                  <Ionicons name="navigate" size={16} color="#757575" />
                </TouchableOpacity>
              );
            }
            return null;
          }}
          predefinedPlaces={frequentLocations.map(location => ({
            description: location,
            structured_formatting: {
              main_text: location,
              secondary_text: '',
            },
          }))}
          currentLocation={false}
          currentLocationLabel="Current location"
          debounce={300}
        />
      ) : (
        <TouchableOpacity
          style={[styles.inputContainer]}
          onPress={() => setIsEditing(true)}
        >
          <Ionicons name="location-outline" size={16} color="#757575" style={styles.icon} />
          <Text style={[typography.body, styles.valueText]} numberOfLines={1}>
            {value}
          </Text>
          {onPinPress && (
            <TouchableOpacity onPress={onPinPress} style={styles.pinButton}>
              <Ionicons name="navigate" size={16} color="#757575" />
            </TouchableOpacity>
          )}
        </TouchableOpacity>
      )}
    </View>
  );
};

const styles = StyleSheet.create({
  container: {
    position: 'relative',
    zIndex: 1,
    flex: 1,
  },
  inputContainer: {
    flexDirection: 'row',
    alignItems: 'center',
    backgroundColor: '#fff',
    borderColor: '#757575',
    borderWidth: 1,
    borderRadius: 12,
    paddingHorizontal: 12,
    height: 36,
  },
  autocompleteContainer: {
    flex: 1,
  },
  input: {
    height: 36,
    marginTop: 0,
    marginBottom: 0,
    paddingTop: 0,
    paddingBottom: 0,
    borderWidth: 1,
    borderColor: '#757575',
    borderRadius: 12,
    paddingHorizontal: 12,
    backgroundColor: '#fff',
  },
  icon: {
    marginRight: 8,
    marginLeft: Platform.select({ ios: 4, android: 8 }),
  },
  pinButton: {
    padding: 4,
  },
  listView: {
    position: 'absolute',
    top: 36,
    left: 0,
    right: 0,
    backgroundColor: '#fff',
    borderRadius: 12,
    borderWidth: 1,
    borderColor: '#E5E5E5',
    maxHeight: 200,
    zIndex: 1000,
    shadowColor: '#000',
    shadowOffset: { width: 0, height: 2 },
    shadowOpacity: 0.1,
    shadowRadius: 4,
    elevation: 3,
  },
  suggestion: {
    padding: 12,
    borderBottomWidth: 1,
    borderBottomColor: '#F5F5F5',
  },
  valueText: {
    flex: 1,
  },
});
